import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function ImageAnalyzer() {
  const [selectedImage, setSelectedImage] = useState(null);
  const [preview, setPreview] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [results, setResults] = useState(null);
  const navigate = useNavigate();

  const handleImageSelect = (e) => {
    const file = e.target.files?.[0];
    if (file) {
      setSelectedImage(file);
      const reader = new FileReader();
      reader.onload = (event) => {
        setPreview(event.target?.result);
      };
      reader.readAsDataURL(file);
      setError('');
      setResults(null);
    }
  };

  const handleAnalyze = async () => {
    if (!selectedImage) {
      setError('Please select an image first');
      return;
    }

    setLoading(true);
    setError('');
    setResults(null);

    try {
      compressImage(selectedImage, async (compressedBase64) => {
        const response = await axios.post('/api/ai/analyze-image', {
          image: compressedBase64,
          imageType: 'image/jpeg'
        });

        const productsResponse = await axios.get('/api/products');
        const allProducts = productsResponse.data;

        const keywords = response.data.keywords || [];
        const matchingProducts = allProducts.filter(product => {
          const productName = product.name.toLowerCase();
          const productCategory = (product.category || '').toLowerCase();

          return keywords.some(keyword => {
            const kw = keyword.toLowerCase();
            return productName.includes(kw) || productCategory.includes(kw);
          });
        });

        setResults({
          analysis: response.data.analysis,
          keywords: keywords,
          fabric: response.data.fabric,
          item: response.data.item,
          products: matchingProducts.slice(0, 9)
        });

        setLoading(false);
      });
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to analyze image');
      console.error('Error:', err);
      setLoading(false);
    }
  };

  const compressImage = (file, callback) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target.result;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        let width = img.width;
        let height = img.height;

        const maxDim = 2048;
        if (width > height) {
          if (width > maxDim) {
            height = Math.round((height * maxDim) / width);
            width = maxDim;
          }
        } else {
          if (height > maxDim) {
            width = Math.round((width * maxDim) / height);
            height = maxDim;
          }
        }

        canvas.width = width;
        canvas.height = height;

        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, width, height);

        const compressedBase64 = canvas.toDataURL('image/jpeg', 0.85).split(',')[1];
        callback(compressedBase64);
      };
    };
  };

  const handleClear = () => {
    setSelectedImage(null);
    setPreview(null);
    setResults(null);
    setError('');
  };

  return (
    <div style={{ minHeight: '100vh', backgroundColor: '#fff' }}>
      {/* Header */}
      <div style={{
        textAlign: 'center',
        padding: '50px 40px 30px',
        borderBottom: '1px solid #e0e0e0'
      }}>
        <h1 style={{
          fontSize: '48px',
          fontWeight: '200',
          letterSpacing: '2px',
          color: '#000',
          margin: '0 0 15px 0',
          textTransform: 'uppercase'
        }}>
          ✨ Style Discovery
        </h1>
        <p style={{
          fontSize: '14px',
          color: '#666',
          margin: '0',
          maxWidth: '600px',
          marginLeft: 'auto',
          marginRight: 'auto'
        }}>
          Upload a fashion photo and let our AI analyze the fabric, color, and style to find perfect matches in our collection
        </p>
      </div>

      {/* Main Content */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: '250px 1fr',
        gap: '50px',
        padding: '50px 50px',
        maxWidth: '1400px',
        marginLeft: 'auto',
        marginRight: 'auto'
      }}>
        {/* Left Sidebar - Upload */}
        <div>
          <h2 style={{
            fontSize: '12px',
            fontWeight: '600',
            letterSpacing: '1px',
            color: '#000',
            margin: '0 0 25px 0',
            textTransform: 'uppercase'
          }}>
            📸 Upload
          </h2>

          <div
            onDragOver={(e) => e.preventDefault()}
            onDrop={(e) => {
              e.preventDefault();
              const file = e.dataTransfer.files[0];
              if (file) {
                const event = { target: { files: [file] } };
                handleImageSelect(event);
              }
            }}
            style={{
              border: '2px dashed #ddd',
              borderRadius: '8px',
              padding: '40px 20px',
              textAlign: 'center',
              cursor: 'pointer',
              transition: 'all 0.3s',
              backgroundColor: preview ? '#f5f5f5' : '#fafafa'
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.borderColor = '#000';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.borderColor = '#ddd';
            }}
          >
            <input
              type="file"
              accept="image/*"
              onChange={handleImageSelect}
              style={{ display: 'none' }}
              id="image-input"
            />

            <label htmlFor="image-input" style={{ cursor: 'pointer', display: 'block' }}>
              {preview ? (
                <div>
                  <img
                    src={preview}
                    alt="Preview"
                    style={{
                      maxWidth: '100%',
                      maxHeight: '200px',
                      marginBottom: '10px',
                      borderRadius: '4px'
                    }}
                  />
                  <p style={{ fontSize: '11px', color: '#999', margin: '5px 0' }}>
                    Click to change
                  </p>
                </div>
              ) : (
                <div>
                  <div style={{ fontSize: '32px', marginBottom: '10px' }}>📸</div>
                  <p style={{
                    fontSize: '12px',
                    color: '#000',
                    margin: '0 0 5px 0',
                    fontWeight: '500'
                  }}>
                    Click to upload
                  </p>
                  <p style={{
                    fontSize: '11px',
                    color: '#999',
                    margin: '0'
                  }}>
                    or drag and drop
                  </p>
                </div>
              )}
            </label>
          </div>

          {selectedImage && (
            <div style={{ marginTop: '20px', display: 'flex', gap: '10px', flexDirection: 'column' }}>
              <button
                onClick={handleAnalyze}
                disabled={loading}
                style={{
                  padding: '12px 16px',
                  backgroundColor: loading ? '#999' : '#000',
                  color: '#fff',
                  border: 'none',
                  fontSize: '11px',
                  fontWeight: '600',
                  letterSpacing: '0.8px',
                  textTransform: 'uppercase',
                  cursor: loading ? 'not-allowed' : 'pointer',
                  borderRadius: '4px',
                  transition: 'all 0.3s'
                }}
              >
                {loading ? '⏳ Analyzing...' : '✨ Analyze'}
              </button>

              <button
                onClick={handleClear}
                style={{
                  padding: '12px 16px',
                  backgroundColor: '#fff',
                  color: '#000',
                  border: '1px solid #ddd',
                  fontSize: '11px',
                  fontWeight: '600',
                  letterSpacing: '0.8px',
                  textTransform: 'uppercase',
                  cursor: 'pointer',
                  borderRadius: '4px',
                  transition: 'all 0.3s'
                }}
                onMouseEnter={(e) => {
                  e.target.style.backgroundColor = '#000';
                  e.target.style.color = '#fff';
                }}
                onMouseLeave={(e) => {
                  e.target.style.backgroundColor = '#fff';
                  e.target.style.color = '#000';
                }}
              >
                Clear
              </button>
            </div>
          )}
        </div>

        {/* Right Content Area */}
        <div>
          {/* Analysis Section */}
          <div style={{ marginBottom: '50px' }}>
            <h2 style={{
              fontSize: '12px',
              fontWeight: '600',
              letterSpacing: '1px',
              color: '#000',
              margin: '0 0 25px 0',
              textTransform: 'uppercase'
            }}>
              🤖 Analysis
            </h2>

            <div style={{
              backgroundColor: '#f9f9f9',
              padding: '30px',
              borderRadius: '8px',
              minHeight: '250px',
              border: '1px solid #e0e0e0'
            }}>
              {loading ? (
                <div style={{ textAlign: 'center', padding: '40px 0' }}>
                  <div style={{ fontSize: '40px', marginBottom: '15px', animation: 'pulse 2s infinite' }}>🤖</div>
                  <p style={{ fontSize: '13px', color: '#666' }}>Analyzing your fashion item...</p>
                </div>
              ) : results ? (
                <div>
                  {(results.item || results.fabric) && (
                    <div style={{ display: 'flex', gap: '8px', marginBottom: '20px', flexWrap: 'wrap' }}>
                      {results.item && (
                        <div style={{
                          display: 'inline-block',
                          backgroundColor: '#000',
                          color: '#fff',
                          padding: '6px 12px',
                          fontSize: '10px',
                          fontWeight: '600',
                          borderRadius: '4px',
                          textTransform: 'uppercase'
                        }}>
                          {results.item}
                        </div>
                      )}
                      {results.fabric && (
                        <div style={{
                          display: 'inline-block',
                          backgroundColor: '#333',
                          color: '#fff',
                          padding: '6px 12px',
                          fontSize: '10px',
                          fontWeight: '600',
                          borderRadius: '4px',
                          textTransform: 'uppercase'
                        }}>
                          {results.fabric}
                        </div>
                      )}
                    </div>
                  )}

                  <p style={{
                    fontSize: '13px',
                    color: '#333',
                    lineHeight: '1.6',
                    margin: '0 0 15px 0'
                  }}>
                    {results.analysis}
                  </p>

                  {results.keywords && results.keywords.length > 0 && (
                    <div>
                      <p style={{
                        fontSize: '10px',
                        fontWeight: '600',
                        color: '#666',
                        textTransform: 'uppercase',
                        margin: '0 0 10px 0'
                      }}>
                        Key Elements
                      </p>
                      <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px' }}>
                        {results.keywords.map((keyword, idx) => (
                          <span
                            key={idx}
                            style={{
                              backgroundColor: '#e8e8e8',
                              color: '#333',
                              padding: '4px 8px',
                              fontSize: '10px',
                              borderRadius: '3px',
                              textTransform: 'capitalize'
                            }}
                          >
                            {keyword}
                          </span>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              ) : (
                <p style={{ fontSize: '13px', color: '#999', textAlign: 'center', margin: '80px 0' }}>
                  Upload an image to see AI analysis
                </p>
              )}

              {error && (
                <div style={{
                  padding: '12px',
                  backgroundColor: '#ffebee',
                  color: '#d32f2f',
                  fontSize: '11px',
                  borderRadius: '4px',
                  marginTop: '15px'
                }}>
                  {error}
                </div>
              )}
            </div>
          </div>

          {/* Products Section */}
          {results && results.products.length > 0 && (
            <div>
              <h2 style={{
                fontSize: '12px',
                fontWeight: '600',
                letterSpacing: '1px',
                color: '#000',
                margin: '0 0 25px 0',
                textTransform: 'uppercase'
              }}>
                🛍️ Similar Products
              </h2>

              <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(3, 1fr)',
                gap: '30px'
              }}>
                {results.products.map(product => (
                  <div
                    key={product._id}
                    onClick={() => navigate(`/product/${product._id}`)}
                    style={{
                      cursor: 'pointer',
                      transition: 'transform 0.3s'
                    }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.transform = 'translateY(-5px)';
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.transform = 'translateY(0)';
                    }}
                  >
                    <div style={{
                      aspectRatio: '1',
                      backgroundColor: '#e8e8e8',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      overflow: 'hidden',
                      marginBottom: '15px',
                      borderRadius: '4px'
                    }}>
                      <img
                        src={product.media?.featured || `/products/${product._id}.jpg`}
                        alt={product.name}
                        style={{
                          width: '100%',
                          height: '100%',
                          objectFit: 'cover'
                        }}
                      />
                    </div>

                    <h4 style={{
                      fontSize: '11px',
                      fontWeight: '600',
                      letterSpacing: '0.5px',
                      color: '#000',
                      margin: '0 0 8px 0',
                      textTransform: 'uppercase'
                    }}>
                      {product.name}
                    </h4>
                    <p style={{
                      fontSize: '12px',
                      fontWeight: '500',
                      color: '#000',
                      margin: '0'
                    }}>
                      ${product.price}
                    </p>
                  </div>
                ))}
              </div>
            </div>
          )}

          {results && results.products.length === 0 && (
            <div style={{
              padding: '40px',
              textAlign: 'center',
              backgroundColor: '#f9f9f9',
              borderRadius: '8px'
            }}>
              <p style={{ fontSize: '13px', color: '#999' }}>
                No matching products found. Try uploading a different image.
              </p>
            </div>
          )}
        </div>
      </div>

      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.5; }
        }
      `}</style>
    </div>
  );
}

export default ImageAnalyzer;
